#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <cuda_runtime.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

__global__ void jacobi_kernel(const float* f_old, float* f, float* error_array) {
    int i = blockIdx.x * blockDim.x + threadIdx.x + 1;
    int j = blockIdx.y * blockDim.y + threadIdx.y + 1;

    if (i >= 1 && i <= N - 2 && j >= 1 && j <= N - 2) {
        float t = 0.25f * (f_old[IDX(i - 1, j)] +
                           f_old[IDX(i + 1, j)] +
                           f_old[IDX(i, j - 1)] +
                           f_old[IDX(i, j + 1)]);
        float df = t - f_old[IDX(i, j)];
        f[IDX(i, j)] = t;
        error_array[IDX(i, j)] = df * df;
    }
}

__global__ void copy_kernel(const float* f, float* f_old) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i >= 1 && i <= N - 2 && j >= 1 && j <= N - 2) {
        f_old[IDX(i, j)] = f[IDX(i, j)];
    }
}

void initialize_data(float* f) {
    for (int j = 0; j < N; ++j) {
        for (int i = 0; i < N; ++i) {
            if (0 == i || N - 1 == i) {
                f[IDX(i, j)] = sinf(j * 2 * M_PI / (N - 1));
            } else if (0 == j || N - 1 == j) {
                f[IDX(i, j)] = sinf(i * 2 * M_PI / (N - 1));
            } else {
                f[IDX(i, j)] = 0.0f;
            }
        }
    }
}

float reduce_error(float* d_error_array) {
    // Simple reduction on host after copying error array from device
    float* h_error_array = (float*)malloc(N * N * sizeof(float));
    cudaMemcpy(h_error_array, d_error_array, N * N * sizeof(float), cudaMemcpyDeviceToHost);

    double sum = 0.0;
    for (int j = 1; j < N - 1; ++j) {
        for (int i = 1; i < N - 1; ++i) {
            sum += h_error_array[IDX(i, j)];
        }
    }
    free(h_error_array);
    return sqrtf((float)(sum / (N * N)));
}

int main() {
    auto start_time = std::chrono::steady_clock::now();

    float* f = (float*)aligned_alloc(64, N * N * sizeof(float));
    float* f_old = (float*)aligned_alloc(64, N * N * sizeof(float));

    float error = std::numeric_limits<float>::max();
    const float tolerance = 1.e-5f;

    initialize_data(f);
    initialize_data(f_old);

    float *d_f, *d_f_old, *d_error_array;
    cudaMalloc(&d_f, N * N * sizeof(float));
    cudaMalloc(&d_f_old, N * N * sizeof(float));
    cudaMalloc(&d_error_array, N * N * sizeof(float));

    cudaMemcpy(d_f, f, N * N * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_f_old, f_old, N * N * sizeof(float), cudaMemcpyHostToDevice);

    const int max_iters = 10000;
    int num_iters = 0;

    dim3 blockDim(16, 16);
    dim3 gridDim((N - 2 + blockDim.x - 1) / blockDim.x, (N - 2 + blockDim.y - 1) / blockDim.y);

    auto start = std::chrono::steady_clock::now();

    while (tolerance < error && max_iters > num_iters) {
        cudaMemset(d_error_array, 0, N * N * sizeof(float));

        jacobi_kernel<<<gridDim, blockDim>>>(d_f_old, d_f, d_error_array);
        cudaDeviceSynchronize();

        error = reduce_error(d_error_array);

        copy_kernel<<<gridDim, blockDim>>>(d_f, d_f_old);
        cudaDeviceSynchronize();

        if (0 == num_iters % 1000) {
            std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
        }

        ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

    if (tolerance >= error && max_iters > num_iters) {
        std::cout << "PASS" << std::endl;
    } else {
        std::cout << "FAIL" << std::endl;
        cudaFree(d_f);
        cudaFree(d_f_old);
        cudaFree(d_error_array);
        free(f);
        free(f_old);
        return -1;
    }

    cudaFree(d_f);
    cudaFree(d_f_old);
    cudaFree(d_error_array);
    free(f);
    free(f_old);

    auto end_time = std::chrono::steady_clock::now();
    auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
    double duration = total_time * 1e-9;
    std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

    return 0;
}
